def _transcribe_baidu_chunked(filepath, token):
    """百度语音分段转写 - 带重试机制和returncode检查"""
    import tempfile, subprocess, shutil, time as _time
    tmpdir = tempfile.mkdtemp()
    chunk_pattern = os.path.join(tmpdir, 'chunk_%03d.wav')
    chunks = []

    # 方案1：用ffmpeg分段（检查returncode）
    ffmpeg_ok = False
    try:
        result = subprocess.run([
            'ffmpeg', '-i', filepath, '-f', 'segment', '-segment_time', '50',
            '-ac', '1', '-ar', '16000', '-acodec', 'pcm_s16le', '-y', chunk_pattern
        ], capture_output=True, timeout=120)
        if result.returncode == 0:
            chunks = sorted([os.path.join(tmpdir, f) for f in os.listdir(tmpdir) if f.startswith('chunk_')])
            if chunks:
                ffmpeg_ok = True
    except (FileNotFoundError, OSError):
        pass
    except Exception:
        pass

    # 方案2：纯Python WAV切分（Android无ffmpeg时）
    if not ffmpeg_ok:
        chunks = _split_wav_python(filepath, tmpdir, 50)

    if not chunks:
        shutil.rmtree(tmpdir, ignore_errors=True)
        raise Exception('音频分段失败')

    results = []
    for chunk in chunks:
        with open(chunk, 'rb') as f:
            data = f.read()
        if len(data) < 100:
            continue

        payload = {
            'format': 'wav', 'rate': 16000, 'channel': 1,
            'cuid': 'voicedoc_apk', 'token': token,
            'speech': base64.b64encode(data).decode(),
            'len': len(data), 'dev_pid': 1537
        }

        # 重试机制：2次尝试，间隔1秒
        for attempt in range(2):
            try:
                r = requests.post('https://vop.baidu.com/server_api',
                    json=payload, timeout=60).json()
                if r.get('err_no', -1) == 0:
                    text = ''.join(r.get('result', []))
                    if text.strip():
                        results.append(text)
                    break
                elif r.get('err_no') == 3301:
                    # 音频质量过差，跳过此段
                    break
                elif attempt == 0:
                    _time.sleep(1)
                    continue
            except Exception:
                if attempt == 0:
                    _time.sleep(1)

    # 清理临时目录
    shutil.rmtree(tmpdir, ignore_errors=True)

    return ''.join(results) if results else '分段识别全部失败'


def _split_wav_python(filepath, output_dir, segment_sec):
    """纯Python WAV切分，支持完整格式转换：
    - 多声道 → 单声道（取平均）
    - 任意采样率 → 16kHz（线性插值）
    - 8/16/32bit → 16bit PCM
    """
    try:
        import wave, struct

        with wave.open(filepath, 'rb') as wf:
            n_channels = wf.getnchannels()
            sample_width = wf.getsampwidth()
            framerate = wf.getframerate()
            n_frames = wf.getnframes()
            all_data = wf.readframes(n_frames)

        need_convert = (n_channels != 1 or sample_width != 2 or framerate != 16000)

        if need_convert:
            # 解析原始采样到统一的int16范围
            if sample_width == 1:
                # 8bit unsigned → signed 16bit
                fmt = '%dB' % len(all_data)
                raw = struct.unpack(fmt, all_data)
                samples = [(s - 128) * 256 for s in raw]
            elif sample_width == 2:
                # 16bit signed
                fmt = '%dh' % (len(all_data) // 2)
                samples = list(struct.unpack(fmt, all_data))
            elif sample_width == 4:
                # 32bit signed → 16bit (right shift 16)
                fmt = '%di' % (len(all_data) // 4)
                raw = struct.unpack(fmt, all_data)
                samples = [s >> 16 for s in raw]
            else:
                # 未知位深度，尝试按16bit解析
                fmt = '%dh' % (len(all_data) // 2)
                samples = list(struct.unpack(fmt, all_data))

            # 多声道 → 单声道（取各声道平均值）
            if n_channels > 1:
                mono = []
                for i in range(0, len(samples), n_channels):
                    chunk = samples[i:i + n_channels]
                    mono.append(sum(chunk) // len(chunk))
                samples = mono

            # 重采样到16kHz（线性插值）
            if framerate != 16000:
                ratio = framerate / 16000
                new_len = int(len(samples) / ratio)
                resampled = []
                for i in range(new_len):
                    src_idx = i * ratio
                    idx = int(src_idx)
                    frac = src_idx - idx
                    if idx + 1 < len(samples):
                        val = int(samples[idx] * (1 - frac) + samples[idx + 1] * frac)
                    elif idx < len(samples):
                        val = samples[idx]
                    else:
                        break
                    resampled.append(max(-32768, min(32767, val)))
                samples = resampled

            # 重新编码为16bit PCM
            all_data = struct.pack('%dh' % len(samples), *samples)
            framerate = 16000
            n_channels = 1
            sample_width = 2

        # 按段切分写出WAV文件
        chunk_frames = int(framerate * segment_sec)
        bytes_per_frame = n_channels * sample_width
        chunk_bytes = chunk_frames * bytes_per_frame
        min_bytes = bytes_per_frame * framerate  # 最少1秒

        chunks = []
        for i in range(0, len(all_data), chunk_bytes):
            chunk_data = all_data[i:i + chunk_bytes]
            if len(chunk_data) < min_bytes:
                continue
            path = os.path.join(output_dir, 'chunk_%03d.wav' % len(chunks))
            with wave.open(path, 'wb') as out:
                out.setnchannels(1)
                out.setsampwidth(2)
                out.setframerate(16000)
                out.writeframes(chunk_data)
            chunks.append(path)
        return chunks
    except Exception:
        return []


# ===== Groq Whisper =====
GROQ_BUILTIN_KEY = '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'

def transcribe_groq(filepath, api_key=''):
    """Groq Whisper API - 内置密钥，无需用户配置"""
    if not api_key:
        api_key = GROQ_BUILTIN_KEY

    with open(filepath, 'rb') as f:
        resp = requests.post('https://api.groq.com/openai/v1/audio/transcriptions',
            headers={'Authorization': 'Bearer %s' % api_key},
            files={'file': (os.path.basename(filepath), f, 'audio/wav')},
            data={'model': 'whisper-large-v3', 'language': 'zh',
                  'response_format': 'text'},
            timeout=180)

    if resp.status_code != 200:
        raise Exception('Groq API错误 HTTP %d: %s' % (resp.status_code, resp.text[:200]))

    result = resp.text
    if not result or result.startswith('{"error"'):
        raise Exception('Groq识别失败: %s' % result[:200])

    return result


# ===== FunASR 局域网 =====
def transcribe_funasr(filepath, server_url):
    """FunASR局域网服务"""
    try:
        r = requests.get('%s/health' % server_url, timeout=3)
        if r.status_code != 200:
            raise Exception('FunASR服务未响应')
    except requests.exceptions.ConnectionError:
        raise Exception('无法连接FunASR服务(%s)\n请确认手机和电脑在同一WiFi' % server_url)

    with open(filepath, 'rb') as f:
        resp = requests.post('%s/transcribe_file' % server_url,
            files={'file': (os.path.basename(filepath), f)}, timeout=600)

    if resp.status_code == 404:
        resp = requests.post('%s/transcribe' % server_url,
            json={'file_path': os.path.abspath(filepath)}, timeout=600)

    data = resp.json()
    if not data.get('success'):
        raise Exception(data.get('error', 'FunASR转写失败'))
    return data.get('text', '')


# ===== OpenAI Whisper =====
def transcribe_openai(filepath, api_key=''):
    """OpenAI Whisper API"""
    if not api_key:
        raise Exception('请先在设置中配置OpenAI API Key')

    with open(filepath, 'rb') as f:
        resp = requests.post('https://api.openai.com/v1/audio/transcriptions',
            headers={'Authorization': 'Bearer %s' % api_key},
            files={'file': (os.path.basename(filepath), f, 'audio/wav')},
            data={'model': 'whisper-1', 'response_format': 'text'},
            timeout=120)

    if resp.status_code != 200:
        raise Exception('OpenAI API错误 HTTP %d: %s' % (resp.status_code, resp.text[:200]))

    result = resp.text
    if not result or result.startswith('{"error'):
        raise Exception('OpenAI识别失败: %s' % result[:200])

    return result


# ===== 统一转录入口（Python侧，非Sherpa） =====
def transcribe(filepath, provider, extra_arg=''):
    """Python端ASR转录（百度/Groq/FunASR/OpenAI）"""
    if provider == 'baidu_builtin':
        return transcribe_baidu(filepath)
    elif provider == 'groq_whisper':
        return transcribe_groq(filepath, extra_arg or GROQ_BUILTIN_KEY)
    elif provider == 'funasr':
        return transcribe_funasr(filepath, extra_arg or 'http://192.168.1.100:8765')
    elif provider == 'openai_whisper':
        return transcribe_openai(filepath, extra_arg)
    else:
        raise Exception('不支持的ASR引擎: %s' % provider)


# ===== 测试ASR连通性 =====
def test_asr(provider, extra_arg=''):
    """测试ASR引擎连通性"""
    try:
        if provider == 'baidu_builtin':
            resp = requests.post('https://aip.baidubce.com/oauth/2.0/token',
                params={'grant_type': 'client_credentials',
                        'client_id': BAIDU_KEY, 'client_secret': BAIDU_SECRET}, timeout=5)
            token = resp.json().get('access_token', '')
            if token:
                return '百度语音: 连接成功，Token已获取'
            return '百度语音: Token获取失败'

        elif provider == 'groq_whisper':
            key = extra_arg if extra_arg else GROQ_BUILTIN_KEY
            resp = requests.get('https://api.groq.com/openai/v1/models',
                headers={'Authorization': 'Bearer %s' % key}, timeout=5)
            if resp.status_code == 200:
                return 'Groq Whisper: API Key有效'
            return 'Groq Whisper: API Key无效 (HTTP %d)' % resp.status_code

        elif provider == 'funasr':
            url = extra_arg or 'http://192.168.1.100:8765'
            resp = requests.get('%s/health' % url, timeout=3)
            if resp.status_code == 200:
                return 'FunASR: 服务连接成功'
            return 'FunASR: 服务未响应'

        elif provider == 'openai_whisper':
            key = extra_arg if extra_arg else ''
            if not key:
                return 'OpenAI Whisper: 请先在设置中配置API Key'
            resp = requests.get('https://api.openai.com/v1/models',
                headers={'Authorization': 'Bearer %s' % key}, timeout=5)
            if resp.status_code == 200:
                return 'OpenAI Whisper: API Key有效'
            return 'OpenAI Whisper: API Key无效 (HTTP %d)' % resp.status_code

        elif provider == 'sherpa_offline':
            return 'Sherpa-ONNX: 离线模型，无需网络连接'
        else:
            return '未知引擎: %s' % provider
    except Exception as e:
        return '测试失败: %s' % str(e)


